%[text] ## Section 6: Emax Pharmacodynamic Model and Efficacy Window
%[text] ### Association of Plasma Concentration and Clinical Effect
%[text] The Emax (Hill) model defines the relationship between plasma concentration $C$ and pharmacological effect $E$.
%[text] In the general form $E(C) = \\frac{E(max) \\cdot C^n}{EC50^n + C^n}$, when $n = 1$ (no cooperativity; typical analgesics and stimulants), it becomes $E(C) = \\frac{E(max) \\cdot C}{EC50 + C}$.
%[text] 
%[text] Therapeutic window guidelines:
%[text] When $C \\geq EC50$, the drug exhibits $\\geq 50\\%$ of its maximum effect (effective range).
%[text] When $C \\geq MTC$ (minimum toxic concentration), side effects may appear.
%[text] Here, $MTC = 8 \\cdot EC50$ is used as an indicative safety margin (code constant MTC\_FACTOR).
%[text] 
%[text] The time above EC50 $T(eff)$ approximates the time window during which the drug exerts a meaningful effect and serves as an indicator of effective dosing intervals.
%[text] Aspirin almost completely disappears within 2 h after a sharp spike, while caffeine shows sustained low concentration exposure for over 12 h from a single dose. The optimal profile depends on clinical goals (acute vs chronic treatment).
EMAX       = 100.0;   % % effect (maximum = 100%)
N_HILL     = 1;       % Hill coefficient (n=1: no cooperativity)
MTC_FACTOR = 8.0;     % MTC = MTC_FACTOR * EC50 (indicative safety margin)
logInfo("Emax PD Analysis (n=%d, Emax=%.0f%%):", N_HILL, EMAX); %[output:385b9479]
logInfo("  %-16s %6s %6s %8s %7s %7s", ... %[output:group:83b3d3bb] %[output:7765b461]
    "Drug", "EC50", "MTC", "T>EC50", "Cmax", "Safe?"); %[output:group:83b3d3bb] %[output:7765b461]
logInfo("  %s", repmat("-", 1, 56)); %[output:8d496dc9]
T_eff  = zeros(1, nDrugs);
isSafe = false(1, nDrugs);
for k = 1:nDrugs %[output:group:41031007]
    C_k   = pkSim(k).C;
    t_k   = pkSim(k).t;
    MTC_k = MTC_FACTOR * pkDB(k).EC50;
    % Time above EC50 (trapezoidal integration of logical indicator)
    above_EC50 = C_k >= pkDB(k).EC50;
    T_eff(k)   = trapz(t_k, double(above_EC50));
    % Safety: peak concentration below indicative MTC
    isSafe(k) = pkSim(k).Cmax < MTC_k;
    logInfo("  %-16s %6.1f %6.1f %8.2f %7.2f %7s", ... %[output:7223f5d3]
        pkDB(k).Name, pkDB(k).EC50, MTC_k, T_eff(k), pkSim(k).Cmax, ... %[output:7223f5d3]
        upper(string(isSafe(k)))); %[output:7223f5d3]
end %[output:group:41031007]
%[text] \--- Figure 5: Effect Profile and $T(eff)$ ---
figure("Name", "R02 Sec6: Emax PD Effect Profiles"); %[output:8daa9619]
tiledlayout(1, 2, TileSpacing="compact"); %[output:8daa9619]
nexttile; %[output:8daa9619]
hold on; %[output:8daa9619]
for k = 1:nDrugs
    C_k = pkSim(k).C;
    E_k = EMAX .* C_k.^N_HILL ./ (pkDB(k).EC50^N_HILL + C_k.^N_HILL);
    plot(pkSim(k).t, E_k, "Color", pkDB(k).Color, ... %[output:8daa9619]
        LineWidth=2, DisplayName=pkDB(k).Name); %[output:8daa9619]
end
yline(50, "--k", "50% E_{max}  (EC50 threshold)", ... %[output:8daa9619]
    LabelHorizontalAlignment="left", HandleVisibility="off"); %[output:8daa9619]
xlabel("Time (h)"); %[output:8daa9619]
ylabel("Effect (% E_{max})"); %[output:8daa9619]
title("Emax PD Effect Profiles"); %[output:8daa9619]
legend(Location="northeast"); %[output:8daa9619]
ylim([0, 105]); %[output:8daa9619]
xlim([0, T_SIM]); %[output:8daa9619]
grid on; %[output:8daa9619]
nexttile; %[output:8daa9619]
colors_rgb = [0.886 0.290 0.200; 0.204 0.541 0.741; ...
              0.596 0.557 0.835; 0.467 0.467 0.467];
bar_h        = bar(T_eff, FaceColor="flat"); %[output:8daa9619]
bar_h.CData  = colors_rgb; %[output:8daa9619]
set(gca, "XTickLabel", {pkDB.Name}, "XTickLabelRotation", 30); %[output:8daa9619]
ylabel("Time Above EC50 (h)"); %[output:8daa9619]
title("Effective Duration per Dose"); %[output:8daa9619]
grid on; %[output:8daa9619]
sgtitle("Emax Pharmacodynamics — Effect vs Time"); %[output:8daa9619]
